# 1. Exportar especificación OpenAPI desde Spring Boot
curl http://localhost:8081/v3/api-docs > openapi.json

# 2. Instalar OpenAPI Generator
npm install -g @openapitools/openapi-generator-cli

# 3. Generar cliente TypeScript/Angular
openapi-generator-cli generate \
  -i openapi.json \
  -g typescript-angular \
  -o src/app/generated-api

# Archivos generados:
# src/app/generated-api/
#   ├── model/
#   │   ├── customer-request.ts
#   │   ├── customer-response.ts
#   │   └── error-response.ts
#   ├── api/
#   │   └── customer.service.ts
#   └── api.module.ts

// customer.service.ts (generado automáticamente)
import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';
import { CustomerResponse } from '../model/customer-response';

@Injectable()
export class CustomerService {
  constructor(private http: HttpClient) {}

  findAll(): Observable<Array<CustomerResponse>> {
    return this.http.get<Array<CustomerResponse>>(
      '/api/v1/customer'
    );
  }

  findById(id: number): Observable<CustomerResponse> {
    return this.http.get<CustomerResponse>(
      `/api/v1/customer/${id}`
    );
  }

  create(body: CustomerRequest): Observable<CustomerResponse> {
    return this.http.post<CustomerResponse>(
      '/api/v1/customer',
      body
    );
  }
}

// app.module.ts - Configurar API Module
import { ApiModule, Configuration } from './generated-api';

@NgModule({
  imports: [
    ApiModule.forRoot(() => new Configuration({
      basePath: 'http://localhost:8081'
    }))
  ]
})
export class AppModule {}

// component.ts - Usar servicio generado
import { CustomerService } from './generated-api/api/customer.service';

export class CustomerListComponent {
  customers: CustomerResponse[] = [];

  constructor(private customerService: CustomerService) {}

  ngOnInit() {
    this.customerService.findAll().subscribe(
      data => this.customers = data,
      error => console.error(error)
    );
  }
}
